import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "How do you calculate a monthly loan payment?", a: "Use the amortization formula M = P[r(1+r)^n]/[(1+r)^n-1], where P is loan amount, r is monthly interest rate, and n is total monthly payments." },
  { q: "What is amortization?", a: "Amortization is the process of paying down a loan with scheduled payments that include both principal and interest." },
  { q: "How does interest rate affect total loan cost?", a: "A higher interest rate increases both the monthly payment and total interest paid over the life of the loan." },
  { q: "What is the difference between principal and interest?", a: "Principal is the amount borrowed. Interest is the cost of borrowing that principal." },
  { q: "Should you choose a shorter or longer loan term?", a: "A shorter term usually means higher monthly payments but lower total interest. A longer term lowers monthly payments but costs more overall." },
];

const money = (n: number) => formatCurrencyValue(n, { maximumFractionDigits: 2 });
const money0 = (n: number) => formatCurrencyValue(n, { maximumFractionDigits: 0 });
const payment = (principal: number, rate: number, months: number) => {
  const r = rate / 100 / 12;
  return r ? principal * r * Math.pow(1 + r, months) / (Math.pow(1 + r, months) - 1) : principal / months;
};

export default function LoanCalculator() {
  useCurrencyVersion();
  const [amount, setAmount] = useState(10000);
  const [rate, setRate] = useState(7);
  const [years, setYears] = useState(5);
  const months = years * 12;
  const monthly = payment(amount, rate, months);
  const totalPayment = monthly * months;
  const totalInterest = totalPayment - amount;

  const schedule = useMemo(() => {
    const rows: Array<{ month: number; payment: number; principal: number; interest: number; balance: number }> = [];
    let balance = amount;
    const r = rate / 100 / 12;
    for (let month = 1; month <= months; month++) {
      const interest = balance * r;
      const principal = Math.min(monthly - interest, balance);
      balance = Math.max(0, balance - principal);
      rows.push({ month, payment: monthly, principal, interest, balance });
    }
    return rows;
  }, [amount, rate, months, monthly]);

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  const comparison = [3, 5, 7, 10, 15].map((r) => ({
    rate: `${r}%`,
    y3: payment(10000, r, 36),
    y5: payment(10000, r, 60),
    y10: payment(10000, r, 120),
    int5: payment(10000, r, 60) * 60 - 10000,
  }));

  return (
    <>
      <SEOHead title="Free Loan Calculator Online - Calculate Monthly Payments and Total Interest Instantly | CalcHive" description="Free online loan calculator. Calculate monthly loan payments, total interest and full amortization schedule for any loan amount, rate and term instantly. 100% free, no signup required." canonical="/loan-calculator" keywords="free loan calculator, loan payment calculator free online, monthly loan payment calculator free, calculate loan interest free, loan amortization calculator free" category="Financial Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Loan Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free loan calculator to calculate loan payments, total interest, and a full amortization schedule instantly.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label><input type="number" value={amount} onChange={(e) => setAmount(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" step="0.1" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Term (years)</label><input type="number" value={years} onChange={(e) => setYears(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${amount}-${rate}-${years}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p><p className="text-6xl font-black text-white tracking-tight" data-testid="result-monthly">{money(monthly)}</p></div>
            <div className="grid grid-cols-3 gap-3 mt-4">{[["Total Payment", totalPayment], ["Total Interest", totalInterest], ["Loan Amount", amount]].map(([label, val]) => <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground">{label}</p><p className="font-extrabold text-foreground">{money(val as number)}</p></div>)}</div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Your Loan Monthly Payment for Free</h2><p className="text-muted-foreground leading-relaxed">Monthly loan payment is calculated from principal, monthly rate, and total number of payments using the standard amortization formula.</p>
          <h2 className="text-2xl font-bold text-foreground">How Interest Rate and Loan Term Affect Your Payment</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Loan Payment on $10,000 at Different Rates and Terms</caption><thead className="bg-muted/60"><tr>{["Interest Rate","3 Years Monthly","5 Years Monthly","10 Years Monthly","Total Interest (5yr)"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparison.map(row => <tr key={row.rate}><td className="py-2.5 px-3 font-semibold">{row.rate}</td><td className="py-2.5 px-3">{money(row.y3)}</td><td className="py-2.5 px-3">{money(row.y5)}</td><td className="py-2.5 px-3">{money(row.y10)}</td><td className="py-2.5 px-3">{money(row.int5)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Personal Loan Payment Calculator for Everyone</h2>
          <div className="overflow-x-auto max-h-96"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Amortization Schedule</caption><thead className="bg-muted/60 sticky top-0"><tr>{["Month","Payment","Principal","Interest","Balance"].map(h => <th key={h} className="text-left py-3 px-3 font-semibold">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{schedule.map(row => <tr key={row.month}><td className="py-2 px-3">{row.month}</td><td className="py-2 px-3">{money(row.payment)}</td><td className="py-2 px-3">{money(row.principal)}</td><td className="py-2 px-3">{money(row.interest)}</td><td className="py-2 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/loan-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


